/// Kernel release reported by `uname -r`.  Must match
/// `src/init/version.rs::UTS_RELEASE` so libkmod's
/// `/lib/modules/$(uname -r)/` lookups land on the staged stubs.
const LUPOS_KERNEL_RELEASE: &str = concat!(env!("CARGO_PKG_VERSION"), "-lupos");
const LUPOS_MODULE_VERMAGIC: &str =
    concat!(env!("CARGO_PKG_VERSION"), "-lupos SMP preempt mod_unload ");

/// Module index filenames libkmod opens from `/lib/modules/<release>/`.
/// Login payloads seed these as empty files so `kmod_new()` succeeds with a
/// "no modules" configuration instead of failing with EOPNOTSUPP. Configured
/// module payloads replace them with the exact depmod-generated indexes. Ref:
/// `vendor/linux/Documentation/kbuild/modules.rst` and libkmod's
/// `kmod_search_moddep()` lookup order.
const LIBKMOD_INDEX_FILES: &[&str] = &[
    "modules.dep",
    "modules.dep.bin",
    "modules.alias",
    "modules.alias.bin",
    "modules.symbols",
    "modules.symbols.bin",
    "modules.builtin",
    "modules.builtin.bin",
    "modules.builtin.alias.bin",
    "modules.builtin.modinfo",
    "modules.devname",
    "modules.order",
    "modules.softdep",
    "modules.weakdep",
];

/// Build the empty `/lib/modules/<release>/<name>` initramfs stubs that
/// keep libkmod happy.  All files have mode 0o100644 and zero-length
/// contents (a legitimate "no modules installed" configuration).
fn libkmod_stub_initramfs_files() -> Vec<InitramfsFile> {
    LIBKMOD_INDEX_FILES
        .iter()
        .map(|name| {
            initramfs_file(
                &format!("lib/modules/{LUPOS_KERNEL_RELEASE}/{name}"),
                0o100644,
                Vec::new(),
            )
        })
        .collect()
}

fn ldconfig_shim_initramfs_files() -> Vec<InitramfsFile> {
    LDCONFIG_SHIM_PATHS
        .iter()
        .map(|path| initramfs_file(path, 0o100755, LDCONFIG_SHIM_SCRIPT.as_bytes()))
        .collect()
}

fn systemd_hook_shim_initramfs_file() -> InitramfsFile {
    initramfs_file(SYSTEMD_HOOK_PATH, 0o100755, SYSTEMD_HOOK_SCRIPT.as_bytes())
}
