/// Run the default build smoke after making sure the selected distro exists.
///
/// `cargo xtask test-boot` (no `--mode`) is the single Public Boot acceptance
/// command (see `ROADMAP.md` — `## Public Boot`).  It must exercise the real
/// systemd / agetty / login / bash chain so the four Public Boot items —
/// real systemd as PID 1, getty@tty1 on the framebuffer tty, root → bash with
/// a Linux-like prompt, and a clean `poweroff` / `reboot` — are validated by
/// the same command users actually run.  The synthetic SysV transcript stays
/// reachable via `cargo xtask test-boot --mode pid1-handoff`.
pub fn run_default_boot_smoke() -> Result<()> {
    ensure_userland_stage()?;
    run_login_stack_tests()
}

/// Run the real PID1/login/bash gate.
pub fn run_login_stack_tests() -> Result<()> {
    ensure_userland_stage()?;

    let _guard = EnvVarGuard::set(STAGE_REAL_USERLAND_ENV, "1");
    let prompt = "[lupos@lupos ~]$";
    let steps = [
        SerialExpectStep {
            label: "wrong root login",
            wait_for: "login:",
            send: b"root\n",
        },
        SerialExpectStep {
            label: "wrong root password",
            wait_for: "Password:",
            send: b"wrong-password\n",
        },
        SerialExpectStep {
            label: "wrong password rejected",
            wait_for: "Login incorrect",
            send: b"",
        },
        SerialExpectStep {
            label: "login user",
            wait_for: "login:",
            send: b"lupos\n",
        },
        SerialExpectStep {
            label: "login password",
            wait_for: "Password:",
            send: b"lupos\n",
        },
        SerialExpectStep {
            label: "prompt recovery",
            wait_for: prompt,
            send: b"echo login-stack: prompt recovered\n",
        },
        SerialExpectStep {
            label: "clear smoke",
            wait_for: prompt,
            send: b"clear; echo clear-ok\n",
        },
        SerialExpectStep {
            label: "pwd",
            wait_for: prompt,
            send: b"pwd\n",
        },
        SerialExpectStep {
            label: "home env",
            wait_for: prompt,
            send: b"printf 'home=%s\\n' \"$HOME\"\n",
        },
        SerialExpectStep {
            label: "ls-li metadata",
            wait_for: prompt,
            send: b"ls -ldi /bin/ls /etc/passwd /home/lupos\n",
        },
        SerialExpectStep {
            label: "ls-li marker",
            wait_for: prompt,
            send: b"echo login-stack: ls-li metadata ok\n",
        },
        SerialExpectStep {
            label: "whoami",
            wait_for: prompt,
            send: b"whoami\n",
        },
        SerialExpectStep {
            label: "id",
            wait_for: prompt,
            send: b"id\n",
        },
        SerialExpectStep {
            label: "shell",
            wait_for: prompt,
            send: b"echo $SHELL\n",
        },
        SerialExpectStep {
            label: "start ctrl-c target",
            wait_for: prompt,
            send: b"sleep 5\n",
        },
        SerialExpectStep {
            label: "ctrl-c foreground",
            wait_for: "sleep 5",
            send: b"\x03",
        },
        SerialExpectStep {
            label: "job control probe",
            wait_for: prompt,
            send: b"tail -f /dev/null &\n",
        },
        SerialExpectStep {
            label: "jobs while running",
            wait_for: prompt,
            send: b"jobs\n",
        },
        SerialExpectStep {
            label: "stop background job",
            wait_for: prompt,
            send: b"kill -STOP %1\n",
        },
        SerialExpectStep {
            label: "jobs after stop",
            wait_for: prompt,
            send: b"jobs\n",
        },
        SerialExpectStep {
            label: "terminate stopped job",
            wait_for: prompt,
            send: b"kill -TERM %1\n",
        },
        SerialExpectStep {
            label: "terminated job notification",
            wait_for: "Terminated",
            send: b"\n",
        },
        SerialExpectStep {
            label: "login banner",
            wait_for: prompt,
            send: b"echo login-stack: gate ok\n",
        },
        SerialExpectStep {
            label: "logout lupos",
            wait_for: prompt,
            send: b"exit\n",
        },
        SerialExpectStep {
            label: "shutdown root login",
            wait_for: "login:",
            send: b"root\n",
        },
        SerialExpectStep {
            label: "shutdown root password",
            wait_for: "Password:",
            send: b"lupos\n",
        },
        SerialExpectStep {
            label: "root filesystem check",
            wait_for: "[root@lupos /]#",
            // Root logs into / for this boot image so plain `ls` shows the
            // Arch root filesystem instead of an empty-looking /root.
            // Build the marker by concatenation (like the IMA/EVM steps below) so the
            // literal "login-stack: root fs ok" never appears in the echoed command.
            // Otherwise the next step's wait_for matches the command echo and fires its
            // long send while this command's output is still streaming, corrupting it.
            send: b"printf 'home=%s\\n' \"$HOME\" && pwd && ls bin etc usr var >/dev/null && ok='login-stack: root ' && printf '%s\\n' \"${ok}fs ok\"\n",
        },
        SerialExpectStep {
            label: "root filesystem marker",
            wait_for: "login-stack: root fs ok",
            send: b"\n",
        },
        SerialExpectStep {
            label: "shutdown",
            wait_for: "[root@lupos /]#",
            send: b" poweroff -f\n",
        },
    ];
    let run = build_and_run_iso_with_serial_expect(
        BootMode::LoginStackTest,
        RunOptions {
            exit_after_boot: true,
            // The real login/bash gate runs under the full systemd initramfs
            // (~73 MiB). Under a debug-build kernel without KVM acceleration
            // the kernel alone takes ~5 minutes to reach `/sbin/init`, then
            // systemd-260.1 must walk all its generators and sysvinit-compat
            // before the getty fires. A 30-minute budget is enough to cover
            // the slow unaccelerated QEMU path while still bailing on a real hang.
            qemu_timeout: Some(Duration::from_secs(1800)),
            smp_count: 1,
        },
        &steps,
    )?;

    for needle in [
        "login:",
        "Welcome to Lupos.",
        "lupos",
        "uid=1000(lupos)",
        "/bin/bash",
        "[lupos@lupos ~]$",
        "[root@lupos /]#",
        "clear-ok",
        "/home/lupos",
        "home=/home/lupos",
        "home=/root",
        "^C",
        "Running",
        "tail -f /dev/null",
        "sched_clock: Marking stable",
        "Write protecting the kernel read-only data:",
        "x86/mm: Checked W+X mappings: passed, no W+X pages found.",
        "Freeing unused kernel image (initmem) memory:",
        "Freeing unused kernel image (text/rodata gap) memory:",
        "Freeing unused kernel image (rodata/data gap) memory:",
        LOGIN_STACK_BANNER,
    ] {
        if !serial_log_contains(&run.serial_output, needle) {
            bail!(
                "login-stack serial log did not contain {:?}\nserial log:\n{}",
                needle,
                run.serial_output
            );
        }
    }

    for marker in [
        "login-stack: prompt recovered",
        "login-stack: ls-li metadata ok",
        "login-stack: root fs ok",
    ] {
        if !serial_log_has_output_line(&run.serial_output, marker) {
            bail!(
                "login-stack serial log did not contain output marker {:?}\nserial log:\n{}",
                marker,
                run.serial_output
            );
        }
    }

    assert_ls_li_regular_metadata(&run.serial_output, "/bin/ls")?;
    assert_ls_li_regular_metadata(&run.serial_output, "/etc/passwd")?;
    assert_ls_li_directory_owner(&run.serial_output, "/home/lupos", "lupos")?;

    for forbidden in [
        "Failed to spawn executor: Bad file descriptor",
        "Failed at step RUNTIME_DIRECTORY",
        "Failed to start systemd-journald.service",
        "systemd-journald.service: Failed",
    ] {
        if serial_log_contains(&run.serial_output, forbidden) {
            bail!(
                "login-stack serial log contained forbidden systemd startup failure {:?}\nserial log:\n{}",
                forbidden,
                run.serial_output
            );
        }
    }

    Ok(())
}

pub fn run_gui_shell_tests() -> Result<()> {
    bail!("gui-shell was removed; Arch base has no desktop gate")
}

/// Run the graphical userspace gate: LightDM, Xorg fbdev, and XFCE.
///
/// The automated check keeps QEMU headless and uses a temporary serial getty
/// for inspection.  It proves that the graphics root disk boots far enough for
/// systemd to start the greeter and create the X11 socket/log, then launches a
/// full XFCE session and requires its core desktop components.
pub fn run_graphics_x11_tests() -> Result<()> {
    let _graphics_guard = EnvVarGuard::set("LUPOS_USERLAND_GRAPHICS", "1");
    // Use a relative PS/2 mouse (the pointer Lupos drives) rather than the
    // absolute usb-tablet, so the X pointer actually moves.
    let _tablet_guard = EnvVarGuard::set(LUPOS_QEMU_USB_TABLET_ENV, "0");
    ensure_userland_stage()?;

    let _stage_guard = EnvVarGuard::set(STAGE_REAL_USERLAND_ENV, "1");
    let current_cmdline = env::var(LUPOS_KERNEL_CMDLINE_ENV).unwrap_or_default();
    // No `lupos.synthetic_fb`: the GraphicsX11 GRUB config keeps GRUB's real
    // VBE linear framebuffer (`gfxpayload=keep`, 1280x800 preferred) so
    // `/dev/fb0` is the displayed framebuffer — the same path the interactive
    // `--gui` boot uses.
    let serial_cmdline = append_kernel_args(
        &current_cmdline,
        &["systemd.show_status=yes", "lupos.serial_getty=1"],
    );
    let _cmdline_guard = EnvVarGuard::set(LUPOS_KERNEL_CMDLINE_ENV, &serial_cmdline);

    let prompt = "[root@lupos /]#";
    let steps = [
        SerialExpectStep {
            label: "login root",
            wait_for: "login:",
            send: b"root\n",
        },
        SerialExpectStep {
            label: "root password",
            wait_for: "Password:",
            send: b"lupos\n",
        },
        SerialExpectStep {
            label: "root shell",
            wait_for: prompt,
            send: b"sh /usr/libexec/lupos-graphics-x11-probe.sh\n",
        },
        SerialExpectStep {
            label: "shutdown",
            wait_for: prompt,
            send: b"poweroff -f\n",
        },
    ];

    let run = build_and_run_iso_with_serial_expect_display(
        BootMode::GraphicsX11,
        RunOptions {
            exit_after_boot: false,
            qemu_timeout: Some(Duration::from_secs(1800)),
            smp_count: 1,
        },
        &steps,
        "none",
    )?;

    for needle in [
        "graphics-x11: xorg-proc present",
        "graphics-x11: x-socket present",
        "graphics-x11: xorg-log present",
        "graphics-x11: lightdm ok",
        "graphics-x11: greeter ok",
        "graphics-x11: greeter-ready ok",
        "graphics-x11: timeout-sanity ok",
        "graphics-x11: xclient-roundtrip ok",
        "graphics-x11: pointer ok",
        "graphics-x11: pty-roundtrip ok",
        "graphics-x11: xterm-shell ok",
        "graphics-x11: xterm-shell-state XTERM_INTERACTIVE_OK",
        // The pre-glycin gdk-pixbuf loads PNG icons in-process (no glycin
        // subprocess), a private D-Bus session bus round-trips, and the XFCE
        // complete desktop process set actually comes up.
        "graphics-x11: pixbuf ok",
        "graphics-x11: dbus ok",
        "graphics-x11: xfce ok",
        "graphics-x11: xfce-proc xfce4-session",
        "graphics-x11: xfce-proc xfwm4",
        "graphics-x11: xfce-proc xfsettingsd",
        "graphics-x11: xfce-proc xfce4-panel",
        "graphics-x11: xfce-proc xfdesktop",
    ] {
        if !serial_log_contains(&run.serial_output, needle) {
            bail!(
                "graphics-x11 serial log did not contain {:?}\nserial log:\n{}",
                needle,
                run.serial_output
            );
        }
    }
    for forbidden in [
        "graphics-x11: xorg-proc missing",
        "graphics-x11: x-socket missing",
        "graphics-x11: xorg-log missing",
        "graphics-x11: lightdm missing",
        "graphics-x11: greeter missing",
        "graphics-x11: greeter-ready missing",
        "graphics-x11: timeout-sanity unexpected-ok",
        "graphics-x11: timeout-sanity failed",
        "graphics-x11: xclient-roundtrip failed",
        "graphics-x11: xclient-roundtrip missing-xmodmap",
        "graphics-x11: pty-roundtrip failed",
        "graphics-x11: pty-roundtrip no-ptmx",
        "graphics-x11: pty-roundtrip no-script",
        "graphics-x11: xterm-shell failed",
        "graphics-x11: xterm-shell missing-xterm",
        "graphics-x11: xterm-shell missing-bash",
        "graphics-x11: xterm-shell missing-xserver",
        "graphics-x11: pointer not-detected",
        "graphics-x11: pixbuf failed",
        "graphics-x11: dbus failed",
        "graphics-x11: xfce failed",
        "Unrecognized image file format",
        "no screens found",
        "Fatal server error",
    ] {
        if serial_log_contains(&run.serial_output, forbidden) {
            bail!(
                "graphics-x11 serial log contained forbidden marker {:?}\nserial log:\n{}",
                forbidden,
                run.serial_output
            );
        }
    }

    Ok(())
}

