// Path strings for shell scripts come from `shell_path` (native, Linux-only).

/// Give xtask-owned child processes a repository-backed temporary directory.
///
/// Several host tools (notably `grub-mkrescue`) may need substantially more
/// scratch space than a tmpfs-backed `/tmp` provides.  A non-empty TMPDIR set
/// explicitly either on the command or by the user remains authoritative;
/// otherwise children use `<repo>/target/xtask/tmp`.  Setting this only on the
/// child avoids mutating the process-global environment from library/test
/// callers.
fn configure_subprocess_tmpdir(command: &mut Command) -> Result<()> {
    let command_tmpdir: Option<Option<&OsStr>> = command.get_envs().find_map(|(name, value)| {
        if name == OsStr::new(TMPDIR_ENV) {
            Some(value)
        } else {
            None
        }
    });
    let has_explicit_tmpdir = match command_tmpdir {
        Some(Some(value)) => !value.is_empty(),
        // An explicit removal or empty value does not provide a usable child
        // temporary directory, even if the parent has TMPDIR set.
        Some(None) => false,
        None => env::var_os(TMPDIR_ENV).is_some_and(|value| !value.is_empty()),
    };
    if has_explicit_tmpdir {
        return Ok(());
    }

    let temp_dir = xtask_target_dir()?.join("tmp");
    fs::create_dir_all(&temp_dir).with_context(|| {
        format!(
            "failed to create xtask subprocess temporary directory {}",
            temp_dir.display()
        )
    })?;
    command.env(TMPDIR_ENV, temp_dir);
    Ok(())
}

fn run_command(command: &mut Command, label: &str) -> Result<()> {
    configure_subprocess_tmpdir(command)?;
    let rendered = render_command(command);
    let status = command
        .status()
        .with_context(|| format!("failed to spawn {label}: {rendered}"))?;

    if !status.success() {
        bail!("{label} failed with status {status}: {rendered}");
    }

    Ok(())
}

fn run_command_stdout(command: &mut Command, label: &str) -> Result<String> {
    configure_subprocess_tmpdir(command)?;
    let rendered = render_command(command);
    let output = command
        .output()
        .with_context(|| format!("failed to spawn {label}: {rendered}"))?;

    if !output.status.success() {
        bail!(
            "{label} failed with status {}: {}\nstdout:\n{}\nstderr:\n{}",
            output.status,
            rendered,
            String::from_utf8_lossy(&output.stdout),
            String::from_utf8_lossy(&output.stderr)
        );
    }

    String::from_utf8(output.stdout).with_context(|| format!("{label} output is not UTF-8"))
}

/// RAII guard that ensures a QEMU child process is killed when dropped.
///
/// Rust's `std::process::Child` does NOT kill the child on drop — it only
/// closes the handle, leaving the process running as an orphan.  This wrapper
/// calls `kill()` + `wait()` in its `Drop` impl so that QEMU never leaks,
/// even if the caller returns early via `?` or panics.
struct QemuGuard {
    child: Child,
}

impl QemuGuard {
    fn new(child: Child) -> Self {
        Self { child }
    }

    fn try_wait(&mut self) -> std::io::Result<Option<ExitStatus>> {
        self.child.try_wait()
    }

    fn kill(&mut self) -> std::io::Result<()> {
        self.child.kill()
    }

    fn wait(&mut self) -> std::io::Result<ExitStatus> {
        self.child.wait()
    }

    fn id(&self) -> u32 {
        self.child.id()
    }
}

impl Drop for QemuGuard {
    fn drop(&mut self) {
        let _ = self.child.kill();
        let _ = self.child.wait();
    }
}

const QEMU_RUN_LOCK_FILE: &str = "qemu-run.lock";

struct QemuRunLock {
    path: PathBuf,
}

impl QemuRunLock {
    fn acquire() -> Result<Self> {
        let target = xtask_target_dir()?;
        acquire_qemu_run_lock_in(&target)
    }

    fn record_spawn(&self, qemu_pid: u32, rendered: &str) -> Result<()> {
        let repo = repo_root()
            .map(|path| path.display().to_string())
            .unwrap_or_else(|_| "<unknown>".to_string());
        let started = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap_or_default()
            .as_secs();
        let contents = format!(
            "xtask_pid={}\nqemu_pid={qemu_pid}\nstarted_unix={started}\nrepo={repo}\ncommand={rendered}\n",
            std::process::id()
        );
        fs::write(&self.path, contents)
            .with_context(|| format!("failed to update QEMU run lock {}", self.path.display()))
    }
}

impl Drop for QemuRunLock {
    fn drop(&mut self) {
        match fs::remove_file(&self.path) {
            Ok(()) => {}
            Err(err) if err.kind() == std::io::ErrorKind::NotFound => {}
            Err(_) => {}
        }
    }
}

#[derive(Default)]
struct QemuRunLockOwner {
    xtask_pid: Option<u32>,
    qemu_pid: Option<u32>,
    started_unix: Option<u64>,
    repo: Option<String>,
    command: Option<String>,
}

fn parse_qemu_run_lock_owner(contents: &str) -> QemuRunLockOwner {
    let mut owner = QemuRunLockOwner::default();
    for line in contents.lines() {
        let Some((key, value)) = line.split_once('=') else {
            continue;
        };
        let value = value.trim();
        match key.trim() {
            "xtask_pid" => owner.xtask_pid = value.parse().ok(),
            "qemu_pid" => owner.qemu_pid = value.parse().ok(),
            "started_unix" => owner.started_unix = value.parse().ok(),
            "repo" => owner.repo = Some(value.to_string()),
            "command" => owner.command = Some(value.to_string()),
            _ => {}
        }
    }
    owner
}

fn qemu_run_lock_owner_is_active(owner: &QemuRunLockOwner) -> bool {
    owner
        .xtask_pid
        .is_some_and(|pid| process_looks_like_xtask_owner(pid, owner))
        || owner
            .qemu_pid
            .is_some_and(|pid| process_looks_like_qemu_owner(pid, owner))
}

fn qemu_run_lock_owner_has_process_ids(owner: &QemuRunLockOwner) -> bool {
    owner.xtask_pid.is_some() || owner.qemu_pid.is_some()
}

fn process_is_running_conservative(pid: u32) -> bool {
    let mut command = Command::new("sh");
    command
        .arg("-c")
        .arg("kill -0 \"$1\" 2>/dev/null")
        .arg("sh")
        .arg(pid.to_string())
        .stdin(Stdio::null())
        .stdout(Stdio::null())
        .stderr(Stdio::null());
    if configure_subprocess_tmpdir(&mut command).is_err() {
        return true;
    }
    command
        .status()
        .map(|status| status.success())
        .unwrap_or(true)
}

fn process_command_line(pid: u32) -> Option<String> {
    let bytes = fs::read(format!("/proc/{pid}/cmdline")).ok()?;
    if bytes.is_empty() {
        return None;
    }
    Some(
        bytes
            .split(|byte| *byte == 0)
            .filter(|part| !part.is_empty())
            .map(|part| String::from_utf8_lossy(part))
            .collect::<Vec<_>>()
            .join(" "),
    )
}

fn process_looks_like_xtask_owner(pid: u32, owner: &QemuRunLockOwner) -> bool {
    match process_command_line(pid) {
        Some(command_line) => {
            process_start_is_compatible_with_lock(pid, owner)
                && command_line.split_whitespace().any(|part| {
                    Path::new(part)
                        .file_name()
                        .and_then(|name| name.to_str())
                        .is_some_and(|name| name == "xtask" || name.starts_with("xtask-"))
                })
        }
        None => process_is_running_conservative(pid),
    }
}

fn process_looks_like_qemu_owner(pid: u32, owner: &QemuRunLockOwner) -> bool {
    let Some(command_line) = process_command_line(pid) else {
        return process_is_running_conservative(pid);
    };
    if !command_line.contains("qemu-system") {
        return false;
    }
    if !process_start_is_compatible_with_lock(pid, owner) {
        return false;
    }
    if let Some(expected_iso) = owner.command.as_deref().and_then(qemu_command_iso_path) {
        return command_line.contains(expected_iso);
    }
    match owner.repo.as_deref() {
        Some(repo) => command_line.contains(repo),
        None => true,
    }
}

fn qemu_command_iso_path(command: &str) -> Option<&str> {
    command
        .split_whitespace()
        .find(|part| part.ends_with(".iso") && part.contains("/target/xtask/"))
}

fn process_start_is_compatible_with_lock(pid: u32, owner: &QemuRunLockOwner) -> bool {
    let Some(lock_started) = owner.started_unix else {
        return true;
    };
    let Some(process_started) = process_start_unix(pid) else {
        return true;
    };
    lock_started.saturating_add(1) >= process_started
}

fn process_start_unix(pid: u32) -> Option<u64> {
    let stat = fs::read_to_string(format!("/proc/{pid}/stat")).ok()?;
    let after_comm = stat.rsplit_once(") ")?.1;
    let start_ticks = after_comm.split_whitespace().nth(19)?.parse::<u64>().ok()?;
    Some(linux_boot_time_unix()? + start_ticks / clock_ticks_per_second())
}

fn linux_boot_time_unix() -> Option<u64> {
    let stat = fs::read_to_string("/proc/stat").ok()?;
    stat.lines().find_map(|line| {
        let value = line.strip_prefix("btime ")?;
        value.trim().parse::<u64>().ok()
    })
}

fn clock_ticks_per_second() -> u64 {
    let mut command = Command::new("getconf");
    command
        .arg("CLK_TCK")
        .stdin(Stdio::null())
        .stderr(Stdio::null());
    if configure_subprocess_tmpdir(&mut command).is_err() {
        return 100;
    }
    command
        .output()
        .ok()
        .and_then(|output| {
            output
                .status
                .success()
                .then(|| String::from_utf8_lossy(&output.stdout).trim().parse().ok())
                .flatten()
        })
        .unwrap_or(100)
}

fn acquire_qemu_run_lock_in(target: &Path) -> Result<QemuRunLock> {
    fs::create_dir_all(target).with_context(|| format!("failed to create {}", target.display()))?;
    let path = target.join(QEMU_RUN_LOCK_FILE);
    let mut file = loop {
        match fs::OpenOptions::new()
            .write(true)
            .create_new(true)
            .open(&path)
        {
            Ok(file) => break file,
            Err(err) if err.kind() == std::io::ErrorKind::AlreadyExists => {
                let owner =
                    fs::read_to_string(&path).unwrap_or_else(|_| "<unreadable>".to_string());
                let parsed = parse_qemu_run_lock_owner(&owner);
                if !qemu_run_lock_owner_has_process_ids(&parsed)
                    || qemu_run_lock_owner_is_active(&parsed)
                {
                    bail!(
                        "another QEMU run appears active from this repo (lock: {})\n{}\nIf no QEMU process is running, remove the stale lock file and retry.",
                        path.display(),
                        owner.trim_end()
                    );
                }
                match fs::remove_file(&path) {
                    Ok(()) => {
                        eprintln!("warning: removed stale QEMU run lock {}", path.display());
                    }
                    Err(remove_err) if remove_err.kind() == std::io::ErrorKind::NotFound => {}
                    Err(remove_err) => {
                        return Err(remove_err).with_context(|| {
                            format!("failed to remove stale QEMU run lock {}", path.display())
                        });
                    }
                }
            }
            Err(err) => {
                return Err(err)
                    .with_context(|| format!("failed to create QEMU run lock {}", path.display()));
            }
        }
    };

    writeln!(
        file,
        "xtask_pid={}\nqemu_pid=<spawning>",
        std::process::id()
    )
    .with_context(|| format!("failed to write QEMU run lock {}", path.display()))?;
    Ok(QemuRunLock { path })
}

fn spawn_qemu_guard(
    command: &mut Command,
    rendered: &str,
    lock: &QemuRunLock,
    label: &str,
) -> Result<QemuGuard> {
    configure_subprocess_tmpdir(command)?;
    let guard = QemuGuard::new(
        command
            .spawn()
            .with_context(|| format!("failed to spawn {label} QEMU process: {rendered}"))?,
    );
    lock.record_spawn(guard.id(), rendered)?;
    Ok(guard)
}

struct EnvVarGuard {
    name: &'static str,
    previous: Option<String>,
    _env_lock: EnvLockGuard,
}

struct EnvLockState {
    owner: Option<thread::ThreadId>,
    depth: usize,
}

static ENV_LOCK_STATE: Mutex<EnvLockState> = Mutex::new(EnvLockState {
    owner: None,
    depth: 0,
});
static ENV_LOCK_CVAR: Condvar = Condvar::new();

struct EnvLockGuard;

impl EnvLockGuard {
    fn acquire() -> Self {
        let thread_id = thread::current().id();
        let mut state = ENV_LOCK_STATE.lock().unwrap();
        loop {
            match state.owner {
                Some(owner) if owner == thread_id => {
                    state.depth += 1;
                    return Self;
                }
                Some(_) => {
                    state = ENV_LOCK_CVAR.wait(state).unwrap();
                }
                None => {
                    state.owner = Some(thread_id);
                    state.depth = 1;
                    return Self;
                }
            }
        }
    }
}

impl Drop for EnvLockGuard {
    fn drop(&mut self) {
        let thread_id = thread::current().id();
        let mut state = ENV_LOCK_STATE.lock().unwrap();
        assert_eq!(
            state.owner,
            Some(thread_id),
            "EnvLockGuard dropped on a different thread"
        );
        state.depth -= 1;
        if state.depth == 0 {
            state.owner = None;
            ENV_LOCK_CVAR.notify_one();
        }
    }
}

impl EnvVarGuard {
    fn set(name: &'static str, value: &str) -> Self {
        let env_lock = EnvLockGuard::acquire();
        let previous = env::var(name).ok();
        unsafe {
            env::set_var(name, value);
        }
        Self {
            name,
            previous,
            _env_lock: env_lock,
        }
    }
}

impl Drop for EnvVarGuard {
    fn drop(&mut self) {
        unsafe {
            if let Some(previous) = self.previous.as_ref() {
                env::set_var(self.name, previous);
            } else {
                env::remove_var(self.name);
            }
        }
    }
}

fn run_command_with_optional_timeout(
    command: &mut Command,
    serial_log_path: &Path,
    timeout: Option<Duration>,
) -> Result<ExitStatus> {
    let qemu_lock = QemuRunLock::acquire()?;
    match timeout {
        Some(timeout) => run_command_with_timeout(command, serial_log_path, timeout, &qemu_lock),
        None => {
            let rendered = render_command(command);
            let mut guard = spawn_qemu_guard(command, &rendered, &qemu_lock, "standard")?;
            let mut progress = BootProgressReporter::new(serial_log_path);
            progress.serial_log_opened();
            loop {
                if let Some(status) = guard
                    .try_wait()
                    .with_context(|| format!("failed while waiting on QEMU: {rendered}"))?
                {
                    return Ok(status);
                }
                let serial_output = read_serial_log_if_present(serial_log_path);
                progress.observe_log(&serial_output);
                progress.tick();
                thread::sleep(Duration::from_millis(QEMU_POLL_INTERVAL_MS));
            }
        }
    }
}

fn run_command_with_timeout(
    command: &mut Command,
    serial_log_path: &Path,
    timeout: Duration,
    qemu_lock: &QemuRunLock,
) -> Result<ExitStatus> {
    let rendered = render_command(command);
    let mut guard = spawn_qemu_guard(command, &rendered, qemu_lock, "standard")?;
    let mut progress = BootProgressReporter::new(serial_log_path);
    progress.serial_log_opened();
    let deadline = Instant::now() + timeout;

    loop {
        if let Some(status) = guard
            .try_wait()
            .with_context(|| format!("failed while waiting on QEMU: {rendered}"))?
        {
            return Ok(status);
        }
        let serial_output = read_serial_log_if_present(serial_log_path);
        progress.observe_log(&serial_output);

        if Instant::now() >= deadline {
            let _ = guard.kill();
            let _ = guard.wait();

            let timeout_secs = timeout.as_secs();
            if serial_output.is_empty() {
                bail!("QEMU timed out after {timeout_secs}s: {rendered}");
            }

            bail!(
                "QEMU timed out after {timeout_secs}s: {rendered}\npartial serial log:\n{}",
                serial_output
            );
        }

        progress.tick();
        thread::sleep(Duration::from_millis(QEMU_POLL_INTERVAL_MS));
    }
}

fn read_serial_log_if_present(path: &Path) -> String {
    fs::read_to_string(path).unwrap_or_default()
}

fn render_command(command: &Command) -> String {
    let program = command.get_program().to_string_lossy().into_owned();
    let args = command
        .get_args()
        .map(|arg| arg.to_string_lossy().into_owned())
        .collect::<Vec<_>>()
        .join(" ");

    if args.is_empty() {
        program
    } else {
        format!("{program} {args}")
    }
}

pub(crate) fn xtask_target_dir() -> Result<PathBuf> {
    let root = repo_root()?;
    Ok(root.join("target").join("xtask"))
}

pub(crate) fn repo_root() -> Result<PathBuf> {
    if let Some(manifest_dir) = env::var_os("CARGO_MANIFEST_DIR").map(PathBuf::from) {
        if let Some(parent) = manifest_dir.parent() {
            return Ok(parent.to_path_buf());
        }
    }

    for seed in [env::current_exe().ok(), env::current_dir().ok()]
        .into_iter()
        .flatten()
    {
        for candidate in seed.ancestors() {
            if candidate.join("Cargo.toml").is_file()
                && candidate.join("xtask").join("Cargo.toml").is_file()
            {
                return Ok(candidate.to_path_buf());
            }
        }
    }

    bail!(
        "failed to resolve repo root: CARGO_MANIFEST_DIR is not set and no ancestor contains both Cargo.toml and xtask/Cargo.toml"
    )
}

