    #[test]
    fn direct_stage_root_disk_overlay_contains_runtime_files_and_modules() {
        let module_dep_path = format!("lib/modules/{MODULE_VERSION_DIR}/modules.dep");
        let modules = vec![initramfs_file(&module_dep_path, 0o100644, b"dep e1000\n")];
        let files = direct_stage_login_root_disk_overlay_files(
            BootMode::LoginDisplay,
            SYSTEMD_DISK_ROOT_FSTAB,
            &modules,
            Path::new("/nonexistent-login-stage"),
        );

        assert_eq!(
            initramfs_file_bytes(&files, "sbin/init"),
            Some(&b"/usr/lib/systemd/systemd"[..])
        );
        assert_eq!(
            initramfs_file_bytes(&files, "etc/fstab"),
            Some(SYSTEMD_DISK_ROOT_FSTAB.as_bytes())
        );
        assert_eq!(
            initramfs_file_bytes(&files, "etc/modules"),
            Some(etc_modules_from_repo_config().as_slice())
        );
        assert_eq!(
            initramfs_file_bytes(&files, "etc/pacman.d/mirrorlist"),
            Some(ARCH_PACMAN_MIRRORLIST.as_bytes())
        );
        let pacman_xfer = find_initramfs_entry(&files, ARCH_PACMAN_XFER_HELPER)
            .expect("direct-stage root disks must include the pacman transfer helper");
        assert_eq!(pacman_xfer.1 & 0o777, 0o755);
        assert_eq!(
            initramfs_file_bytes(&files, ARCH_PACMAN_XFER_HELPER),
            Some(ARCH_PACMAN_XFER_HELPER_SCRIPT.as_bytes())
        );
        assert!(
            ARCH_PACMAN_XFER_HELPER_SCRIPT.contains("*.sig) exit 1 ;;"),
            "transfer helper must quietly miss optional package signatures"
        );
        let systemd_hook = find_initramfs_entry(&files, SYSTEMD_HOOK_PATH)
            .expect("direct-stage root disks must include the Lupos systemd hook wrapper");
        assert!(initramfs_file_is_regular(systemd_hook));
        assert_eq!(systemd_hook.1 & 0o777, 0o755);
        assert_eq!(
            initramfs_file_bytes(&files, SYSTEMD_HOOK_PATH),
            Some(SYSTEMD_HOOK_SCRIPT.as_bytes())
        );
        assert!(
            SYSTEMD_HOOK_SCRIPT.contains("systemd-detect-virt --chroot >/dev/null 2>/dev/null"),
            "systemd hook wrapper must suppress the broken chroot probe warning"
        );
        assert!(
            SYSTEMD_HOOK_SCRIPT.contains("skip_live_service_hook()")
                && SYSTEMD_HOOK_SCRIPT
                    .contains("live systemd service-manager package hook is disabled on Lupos"),
            "systemd hook wrapper must skip live service-manager hooks"
        );
        for rel in LDCONFIG_SHIM_PATHS {
            let entry = find_initramfs_entry(&files, rel)
                .unwrap_or_else(|| panic!("{rel} ldconfig shim must be in direct-stage overlay"));
            assert!(initramfs_file_is_regular(entry));
            assert_eq!(entry.1 & 0o777, 0o755);
            assert_eq!(
                initramfs_file_bytes(&files, rel),
                Some(LDCONFIG_SHIM_SCRIPT.as_bytes())
            );
        }
        assert_eq!(
            initramfs_file_bytes(&files, "etc/pam.d/common-session"),
            Some(LOGIN_PAM_COMMON_SESSION.as_bytes())
        );
        assert_eq!(
            initramfs_file_bytes(&files, "etc/pam.d/login"),
            Some(LOGIN_PAM_LOGIN.as_bytes())
        );
        assert_eq!(
            initramfs_file_bytes(&files, "etc/profile"),
            Some(LOGIN_PROFILE.as_bytes())
        );
        assert_eq!(
            initramfs_file_bytes(&files, "etc/motd"),
            Some(LOGIN_MOTD.as_bytes())
        );
        assert!(
            find_initramfs_entry(&files, "home/lupos").is_some(),
            "direct-stage root disks must create the lupos home directory"
        );
        assert_eq!(
            initramfs_file_bytes(&files, "home/lupos/.bash_profile"),
            Some(LUPOS_USER_BASH_PROFILE.as_bytes())
        );
        assert!(
            core::str::from_utf8(
                initramfs_file_bytes(&files, "etc/shadow").expect("shadow overlay")
            )
            .expect("shadow utf-8")
            .contains("root:$6$lupos$"),
            "direct-stage root disks must overlay the unlocked Lupos root password"
        );
        assert_eq!(
            initramfs_file_bytes(&files, &module_dep_path),
            Some(&b"dep e1000\n"[..])
        );
        assert!(
            find_initramfs_entry(
                &files,
                "etc/systemd/system/multi-user.target.wants/systemd-journald.service"
            )
            .is_some(),
            "interactive login disks should keep journald enabled"
        );
        let terminal_target = core::str::from_utf8(
            initramfs_file_bytes(&files, "usr/lib/systemd/system/lupos-terminal.target")
                .expect("terminal target staged"),
        )
        .expect("terminal target utf-8");
        assert!(
            terminal_target.contains("systemd-journald-dev-log.socket"),
            "fast terminal target must start journald's /dev/log socket"
        );
        for socket in [
            "etc/systemd/system/sockets.target.wants/systemd-journald.socket",
            "etc/systemd/system/sockets.target.wants/systemd-journald-dev-log.socket",
        ] {
            assert!(
                find_initramfs_entry(&files, socket).is_some(),
                "interactive login disks should enable {socket} so /dev/log captures auth failures"
            );
        }
        let journald_service = core::str::from_utf8(
            initramfs_file_bytes(&files, "usr/lib/systemd/system/systemd-journald.service")
                .expect("journald service override staged"),
        )
        .expect("journald service utf-8");
        assert!(journald_service.contains("Environment=RUNTIME_DIRECTORY=/run/systemd/journal"));
        assert!(journald_service.contains("ExecStart=/usr/lib/systemd/systemd-journald"));
        assert!(journald_service.contains("Type=simple"));
        assert!(!journald_service.contains("Type=notify"));
        assert!(!journald_service.contains("WatchdogSec="));
        assert!(
            journald_service.contains("RuntimeDirectory=systemd/journal systemd/journal/streams")
        );
        assert!(
            !journald_service.contains("SystemCallFilter=")
                && !journald_service.contains("IPAddressDeny="),
            "direct-stage overlay must replace Arch's sandboxed journald service"
        );
    }

    #[test]
    fn critical_runtime_direct_stage_root_disk_overlay_prunes_journald_and_adds_mode_script() {
        let modules = Vec::new();
        let files = direct_stage_login_root_disk_overlay_files(
            BootMode::UserspaceSmokeTest,
            SYSTEMD_DISK_ROOT_FSTAB,
            &modules,
            Path::new("/nonexistent-login-stage"),
        );
        let delete_paths = direct_stage_login_root_disk_delete_paths(BootMode::UserspaceSmokeTest);

        assert_eq!(
            initramfs_file_bytes(&files, USERSPACE_SMOKE_SCRIPT_PATH),
            Some(USERSPACE_SMOKE_SCRIPT.as_bytes())
        );
        assert_eq!(
            initramfs_file_bytes(&files, "root/test.txt"),
            Some(b"data\n".as_slice())
        );
        assert!(
            find_initramfs_entry(
                &files,
                "etc/systemd/system/multi-user.target.wants/systemd-journald.service"
            )
            .is_none(),
            "userspace smoke/stress disks should not enable journald restart churn"
        );
        // The disk-root boot mounts / read-only and lupos-terminal.target
        // skips local-fs.target, so without an explicit want the fstab
        // tmpfs /tmp never mounts and every /tmp write EROFSes.
        assert!(
            find_initramfs_entry(
                &files,
                "etc/systemd/system/lupos-terminal.target.wants/tmp.mount"
            )
            .is_some(),
            "terminal-profile disks must mount the tmpfs /tmp for shell writes"
        );
        assert!(
            delete_paths
                .contains(&"etc/systemd/system/multi-user.target.wants/systemd-journald.service")
        );
        assert!(
            delete_paths.contains(&"var/lib/pacman/db.lck"),
            "cached direct-stage disks must never preserve a stale pacman lock"
        );
    }

    #[test]
    fn login_stack_root_disk_overlay_marks_update_done_without_multi_user_gate() {
        let modules = Vec::new();
        let files = direct_stage_login_root_disk_overlay_files(
            BootMode::LoginStackTest,
            SYSTEMD_DISK_ROOT_FSTAB,
            &modules,
            Path::new("/nonexistent-login-stage"),
        );

        for updated in ["etc/.updated", "var/.updated"] {
            assert!(
                find_initramfs_entry(&files, updated).is_some(),
                "{updated} must mark the login-stack image update-done"
            );
        }
        let default_target = find_initramfs_entry(&files, "etc/systemd/system/default.target")
            .expect("default.target staged");
        assert_eq!(
            default_target.2.as_slice(),
            b"/usr/lib/systemd/system/lupos-terminal.target",
            "login-stack must keep the fast terminal target"
        );
        assert!(
            find_initramfs_entry(&files, SHIPPED_COMMANDS_SCRIPT_PATH).is_none(),
            "login-stack must not include the shipped-commands gate"
        );
    }

    #[test]
    fn graphics_x11_direct_stage_overlay_starts_fbdev_xorg_on_tty1() {
        let files = direct_stage_login_root_disk_overlay_files(
            BootMode::GraphicsX11,
            SYSTEMD_DISK_ROOT_FSTAB,
            &[],
            Path::new("/nonexistent-graphics-stage"),
        );

        let default_target = find_initramfs_entry(&files, "etc/systemd/system/default.target")
            .expect("graphics default target staged");
        assert_eq!(
            default_target.2.as_slice(),
            b"/usr/lib/systemd/system/multi-user.target",
            "graphics-x11 must boot the normal multi-user graph before starting Xorg"
        );

        let xorg_conf = core::str::from_utf8(
            initramfs_file_bytes(&files, "etc/X11/xorg.conf.d/10-lupos-fbdev.conf")
                .expect("fbdev Xorg config staged"),
        )
        .expect("fbdev config utf-8");
        assert!(xorg_conf.contains("Driver \"fbdev\""));
        assert!(xorg_conf.contains("Option \"fbdev\" \"/dev/fb0\""));
        assert!(xorg_conf.contains("Section \"Screen\""));
        assert!(xorg_conf.contains("Screen \"LuposScreen\""));
        assert!(xorg_conf.contains("Option \"AutoAddDevices\" \"false\""));
        // Lupos has no udev seat, so the keyboard is bound explicitly to the
        // kernel evdev node via the classic evdev driver.
        assert!(!xorg_conf.contains("Option \"AllowEmptyInput\""));
        assert!(xorg_conf.contains("Section \"InputDevice\""));
        assert!(xorg_conf.contains("Driver \"evdev\""));
        assert!(xorg_conf.contains("Option \"Device\" \"/dev/input/event0\""));
        assert!(xorg_conf.contains("InputDevice \"LuposKeyboard\" \"CoreKeyboard\""));

        let xinitrc = core::str::from_utf8(
            initramfs_file_bytes(&files, "root/.xinitrc").expect("root xinitrc staged"),
        )
        .expect("xinitrc utf-8");
        // Primary path launches XFCE; twm+xterm remains as the fallback.
        assert!(xinitrc.contains("startxfce4"));
        assert!(xinitrc.contains("xterm"));
        assert!(xinitrc.contains("exec twm"));

        // Graphical login runs through LightDM instead of an auto-started startx.
        let lightdm = core::str::from_utf8(
            initramfs_file_bytes(&files, "usr/lib/systemd/system/lupos-lightdm.service")
                .expect("LightDM service staged"),
        )
        .expect("LightDM unit utf-8");
        assert!(lightdm.contains("while [ ! -e /dev/fb0 ]"));
        assert!(lightdm.contains("mkdir -p /tmp/.X11-unix /run/lightdm"));
        assert!(lightdm.contains("TimeoutStartSec=240s"));
        assert!(lightdm.contains("ExecStart=/usr/bin/lightdm --debug"));
        assert!(lightdm.contains("chown 969:969 /run/lightdm"));
        // LightDM stays outside the full default dependency chain, but Xorg must
        // not race the system bus/logind path it enters before serving clients.
        assert!(lightdm.contains("DefaultDependencies=no"));
        assert!(lightdm.contains("Wants=dbus.socket dbus.service systemd-logind.service"));
        assert!(lightdm.contains(
            "After=systemd-journald.socket systemd-journald.service dbus.socket dbus.service systemd-logind.service"
        ));
        assert!(!lightdm.contains("systemd-user-sessions.service"));

        let lightdm_config = core::str::from_utf8(
            initramfs_file_bytes(&files, "etc/lightdm/lightdm.conf")
                .expect("LightDM config staged"),
        )
        .expect("LightDM config utf-8");
        assert!(lightdm_config.contains("greeter-session=lightdm-gtk-greeter"));
        assert!(lightdm_config.contains("greeter-user=lightdm"));
        assert!(!lightdm_config.contains("greeter-user=root"));
        assert!(lightdm_config.contains("user-authority-in-system-dir=false"));
        assert!(lightdm_config.contains("user-session=xfce"));
        assert!(lightdm_config.contains("/usr/lib/xorg/lupos-xserver"));
        assert!(lightdm_config.contains("-configdir /etc/X11/xorg.conf.d"));
        assert!(!lightdm_config.contains(" -ac"));
        assert!(lightdm_config.contains("greeter-show-manual-login=true"));

        for (path, expected) in [
            ("etc/passwd", "lightdm:x:969:969:Light Display Manager:"),
            ("etc/shadow", "lightdm:!*:"),
            ("etc/group", "lightdm:x:969:"),
            ("etc/gshadow", "lightdm:!::"),
        ] {
            let contents = core::str::from_utf8(
                initramfs_file_bytes(&files, path).expect("LightDM account database staged"),
            )
            .expect("LightDM account database utf-8");
            assert!(contents.contains(expected), "{path} missing {expected}");
        }
        for (path, mode) in [
            ("var/cache/lightdm", 0o40711),
            ("var/lib/lightdm", 0o41770),
            ("var/lib/lightdm-data", 0o41770),
            ("var/log/lightdm", 0o40711),
            ("var/lib/lightdm/.Xauthority", 0o100600),
        ] {
            assert_eq!(
                find_initramfs_entry(&files, path).map(|entry| entry.1),
                Some(mode),
                "{path} must carry LightDM's package directory mode"
            );
        }

        let greeter_config = core::str::from_utf8(
            initramfs_file_bytes(&files, "etc/lightdm/lightdm-gtk-greeter.conf")
                .expect("GTK greeter config staged"),
        )
        .expect("GTK greeter config utf-8");
        assert!(greeter_config.contains("background=/usr/share/backgrounds/lupos-login.png"));
        assert!(greeter_config.contains("theme-name=LuposLogin"));
        assert!(greeter_config.contains("default-session=xfce"));
        assert!(
            initramfs_file_bytes(&files, "usr/share/backgrounds/lupos-login.png")
                .is_some_and(|background| !background.is_empty())
        );

        let xserver = core::str::from_utf8(
            initramfs_file_bytes(&files, "usr/lib/xorg/lupos-xserver")
                .expect("xserver wrapper staged"),
        )
        .expect("xserver wrapper utf-8");
        assert!(xserver.contains("exec /usr/lib/Xorg \"$@\""));
        assert!(xserver.contains("sleep 2"));
        assert!(!xserver.contains("notify_ready"));

        let lightdm_session = core::str::from_utf8(
            initramfs_file_bytes(&files, "usr/libexec/lupos-lightdm-session")
                .expect("LightDM session wrapper staged"),
        )
        .expect("LightDM session wrapper utf-8");
        assert!(lightdm_session.contains("dbus-run-session -- startxfce4"));
        assert!(lightdm_session.contains("mktemp -d"));
        assert!(lightdm_session.contains("chmod 700 \"$XDG_RUNTIME_DIR\""));
        assert!(lightdm_session.contains("stat -c %u"));
        assert!(lightdm_session.contains("xterm"));
        assert!(lightdm_session.contains("exec twm"));

        let probe = core::str::from_utf8(
            initramfs_file_bytes(&files, GRAPHICS_X11_PROBE_SCRIPT_PATH)
                .expect("graphics X11 probe script staged"),
        )
        .expect("graphics X11 probe script utf-8");
        assert!(probe.contains("graphics-x11: process-scan begin"));
        assert!(probe.contains("graphics-x11: direct-xorg start"));
        assert!(probe.contains("/usr/lib/Xorg :0 vt1"));
        assert!(probe.contains("-logfile \"$direct_xorg_log\""));
        assert!(probe.contains("graphics-x11: direct-watchdog begin"));
        assert!(probe.contains("graphics-x11: wait-%s-progress"));
        assert!(probe.contains("wait_for_x 60 service"));
        assert!(probe.contains("wait_for_x 45 direct"));
        assert!(probe.contains("/proc/$direct_xorg_pid"));
        assert!(probe.contains("/proc/$direct_xorg_pid/comm"));
        assert!(probe.contains("socket-backed-xorg"));
        assert!(probe.contains("graphics-x11: xorg-proc"));
        assert!(probe.contains("graphics-x11: xorg-log using-direct"));
        assert!(probe.contains("graphics-x11: lightdm ok"));
        assert!(probe.contains("graphics-x11: greeter ok"));
        assert!(probe.contains("xfce_desktop_ready"));
        assert!(probe.contains("xfce4-panel xfdesktop"));
        assert!(!probe.contains("systemctl "));
        assert!(!probe.contains("journalctl "));
        assert!(probe.contains("/tmp/.X11-unix/X0"));
        assert!(probe.contains("/var/log/Xorg.0.log"));

        assert!(
            find_initramfs_entry(
                &files,
                "etc/systemd/system/multi-user.target.wants/lupos-lightdm.service"
            )
            .is_some(),
            "graphics-x11 must enable the LightDM display manager"
        );
        assert!(
            find_initramfs_entry(
                &files,
                "etc/systemd/system/getty.target.wants/getty@tty1.service"
            )
            .is_none(),
            "graphics-x11 must not race getty@tty1 against Xorg"
        );
        assert!(
            find_initramfs_entry(
                &files,
                "etc/systemd/system/getty.target.wants/serial-getty@ttyS0.service"
            )
            .is_none(),
            "graphics-x11 serial diagnostics must not wait on a udev ttyS0 device unit"
        );
        assert!(
            find_initramfs_entry(
                &files,
                "etc/systemd/system/multi-user.target.wants/lupos-serial-getty.service"
            )
            .is_some(),
            "graphics-x11 should use the udev-independent serial getty when the cmdline enables it"
        );
        for updated in ["etc/.updated", "var/.updated"] {
            assert!(
                find_initramfs_entry(&files, updated).is_some(),
                "graphics-x11 should look update-done before the full multi-user boot"
            );
        }
    }

    #[test]
    fn shipped_commands_root_disk_overlay_boots_multi_user_without_desktop_services() {
        let modules = Vec::new();
        let files = direct_stage_login_root_disk_overlay_files(
            BootMode::ShippedCommandsTest,
            SYSTEMD_DISK_ROOT_FSTAB,
            &modules,
            Path::new("/nonexistent-login-stage"),
        );

        assert_eq!(
            initramfs_file_bytes(&files, SHIPPED_COMMANDS_SCRIPT_PATH),
            Some(SHIPPED_COMMANDS_SCRIPT.as_bytes())
        );
        // The fast lupos-terminal.target skips sysinit/local-fs, so the
        // fstab-generated systemd-remount-fs.service never runs and / stays
        // read-only.  This gate must boot the real multi-user chain.
        let default_target = find_initramfs_entry(&files, "etc/systemd/system/default.target")
            .expect("default.target staged");
        assert_eq!(
            default_target.2.as_slice(),
            b"/usr/lib/systemd/system/multi-user.target",
            "shipped-commands must boot the real multi-user.target chain"
        );
        for kept in ["etc/systemd/system/multi-user.target.wants/systemd-journald.service"] {
            assert!(
                find_initramfs_entry(&files, kept).is_some(),
                "{kept} must be enabled for the systemd-tools gates"
            );
        }
        for omitted in [
            "etc/systemd/system/multi-user.target.wants/systemd-logind.service",
            "etc/systemd/system/multi-user.target.wants/dbus.service",
            "etc/systemd/system/sockets.target.wants/dbus.socket",
        ] {
            assert!(
                find_initramfs_entry(&files, omitted).is_none(),
                "{omitted} must not be required by the Arch base shipped-commands gate"
            );
        }
        let session = find_initramfs_entry(&files, "etc/pam.d/common-session")
            .expect("common-session staged");
        assert!(
            core::str::from_utf8(&session.2)
                .unwrap()
                .contains("session required pam_unix.so"),
            "root login must keep the direct pam_unix session path"
        );
        assert!(
            !core::str::from_utf8(&session.2)
                .unwrap()
                .contains("pam_systemd.so"),
            "Arch base shipped-commands must not wait on logind/dbus session registration"
        );
        // A freshly built image must look update-done (what
        // systemd-update-done.service records), or ConditionNeedsUpdate
        // units (ldconfig, journal-catalog-update, sysusers) run their
        // first-boot rebuilds and stall the boot under TCG.
        for updated in ["etc/.updated", "var/.updated"] {
            assert!(
                find_initramfs_entry(&files, updated).is_some(),
                "{updated} must mark the image update-done"
            );
        }
        // serial-getty@ttyS0 BindsTo dev-ttyS0.device, which only appears
        // once udevd settles; the udev-independent lupos-serial-getty must
        // provide the login prompt, and the device-bound template must not
        // be wanted (two agettys would fight over ttyS0).
        assert!(
            find_initramfs_entry(
                &files,
                "etc/systemd/system/multi-user.target.wants/lupos-serial-getty.service"
            )
            .is_some(),
            "multi-user must want the udev-independent serial getty"
        );
        // Under TCG the whole multi-user burst shares one slow vCPU; if the
        // getty races it, login(1)'s PAM conversation starves past its 60 s
        // timeout.  The gate orders login after the heavy services so the
        // prompt appears on a quiet system.
        let getty_order = find_initramfs_entry(
            &files,
            "etc/systemd/system/lupos-serial-getty.service.d/lupos-shipped-commands.conf",
        )
        .expect("shipped-commands getty ordering drop-in staged");
        let getty_order = core::str::from_utf8(&getty_order.2).unwrap();
        for unit in [
            "systemd-user-sessions.service",
            "systemd-udev-trigger.service",
            "systemd-vconsole-setup.service",
            "systemd-journald.service",
        ] {
            assert!(
                getty_order.contains(unit),
                "gate getty must start after {unit}"
            );
        }
        assert!(
            find_initramfs_entry(
                &files,
                "etc/systemd/system/getty.target.wants/serial-getty@ttyS0.service"
            )
            .is_none(),
            "device-bound serial-getty@ttyS0 must not race lupos-serial-getty"
        );
        // The terminal profile's 15s DefaultTimeoutStartSec kills slow
        // TCG service starts (journald/udevd churn); this gate needs the
        // services, so give them distro-scale timeouts.
        let system_conf =
            find_initramfs_entry(&files, "etc/systemd/system.conf").expect("system.conf staged");
        assert!(
            core::str::from_utf8(&system_conf.2)
                .unwrap()
                .contains("DefaultTimeoutStartSec=180s"),
            "shipped-commands needs TCG-tolerant service start timeouts"
        );
    }

    #[test]
    fn login_display_direct_stage_cache_path_avoids_big_cpio_generation() {
        let source = read_repo_file("xtask/src/lib.rs");
        let direct_builder = source
            .split("fn ensure_direct_stage_login_root_disk")
            .nth(1)
            .expect("direct-stage builder source")
            .split("fn ensure_ext4_root_disk_from_initramfs")
            .next()
            .expect("direct-stage builder body");

        assert_eq!(
            login_root_disk_builder_kind(BootMode::LoginDisplay),
            Some(LoginRootDiskBuilderKind::DirectStage)
        );
        assert!(
            direct_builder.contains(
                "mkfs.ext4 -q -F -L lupos-root -O ^metadata_csum,^64bit -E no_copy_xattrs -d {stage_sh}"
            ),
            "direct-stage builds must format ext4 straight from the staged tree without copying host xattrs"
        );
        assert!(direct_builder.contains("debugfs -w -f {overlay_work_sh}/debugfs.commands"));
        assert!(
            direct_builder.contains("login_root_disk_cache_is_valid"),
            "direct-stage cache hits must validate the ext4 image, not just the manifest"
        );
        assert!(
            source.contains("e2fsck") && source.contains(".arg(\"-fn\")"),
            "root-disk cache validation must run e2fsck -fn before reusing writable images"
        );
        assert!(
            !direct_builder.contains("cp -a {stage_sh}/. {root_sh}/"),
            "direct-stage builds must not duplicate the full staged distro tree"
        );
        assert!(
            !direct_builder.contains("build_initramfs_cpio_unconditional"),
            "direct-stage cache hits must not require the big login CPIO generator"
        );
        assert!(
            !direct_builder.contains("{stem}.cpio"),
            "direct-stage cache hits must not write the old large login-display.cpio"
        );
    }

    #[test]
    fn real_login_root_disks_use_larger_images() {
        for mode in [
            BootMode::Login,
            BootMode::LoginDisplay,
            BootMode::LoginStackTest,
            BootMode::UserspaceSmokeTest,
            BootMode::RuntimeStressTest,
        ] {
            assert_eq!(
                login_root_disk_size(mode),
                (LOGIN_ROOT_DISK_SIZE, LOGIN_ROOT_DISK_BYTES),
                "{mode:?} must have room for the real login rootfs"
            );
        }
        assert_eq!(
            login_root_disk_size(BootMode::DiskRootFsckTest),
            (DISK_ROOT_FSCK_DISK_SIZE, DISK_ROOT_FSCK_DISK_BYTES)
        );
        assert_eq!(
            login_root_disk_size(BootMode::ShippedCommandsTest),
            (
                SHIPPED_COMMANDS_ROOT_DISK_SIZE,
                SHIPPED_COMMANDS_ROOT_DISK_BYTES
            )
        );
        for mode in [BootMode::GraphicsX11, BootMode::GraphicsWayland] {
            assert_eq!(
                login_root_disk_size(mode),
                (GRAPHICS_ROOT_DISK_SIZE, GRAPHICS_ROOT_DISK_BYTES),
                "{mode:?} must have room for X11/Wayland packages"
            );
        }
        assert_eq!(LOGIN_ROOT_DISK_SIZE, "768M");
        assert_eq!(SHIPPED_COMMANDS_ROOT_DISK_SIZE, "768M");
        assert_eq!(GRAPHICS_ROOT_DISK_SIZE, "12G");
        assert!(LOGIN_ROOT_DISK_BYTES > DISK_ROOT_FSCK_DISK_BYTES);
        assert!(SHIPPED_COMMANDS_ROOT_DISK_BYTES > DISK_ROOT_FSCK_DISK_BYTES);
        assert!(GRAPHICS_ROOT_DISK_BYTES > LOGIN_ROOT_DISK_BYTES);
    }

